/* Generic swap function */
void generic_swap(void *a, void *b, size_t size) {
    void *temp = malloc(size);
    if (!temp) return;
    memcpy(temp, a, size);
    memcpy(a, b, size);
    memcpy(b, temp, size);
    free(temp);
}

/* Generic print function */
void print_value(const void *data, char type) {
    switch (type) {
        case 'i': printf("%d", *(const int *)data); break;
        case 'd': printf("%f", *(const double *)data); break;
        case 's': printf("%s", (const char *)data); break;
    }
    printf("\n");
}

int main(void) {
    /* Generic swap works with any type */
    int a = 10, b = 20;
    generic_swap(&a, &b, sizeof(int));
    printf("a=%d b=%d\n", a, b); /* a=20 b=10 */

    double x = 1.5, y = 2.5;
    generic_swap(&x, &y, sizeof(double));
    printf("x=%f y=%f\n", x, y); /* x=2.5 y=1.5 */

    /* Generic print */
    int n = 42;
    double pi = 3.14;
    print_value(&n, 'i');    /* 42 */
    print_value(&pi, 'd');   /* 3.140000 */
    print_value("hello", 's'); /* hello */

    return 0;
}

