#include <stdio.h>

/* Pointer-based strlen */
size_t my_strlen(const char *s) {
    const char *start = s;
    while (*s) s++;
    return (size_t)(s - start);
}

/* Pointer-based strcpy */
char *my_strcpy(char *dst, const char *src) {
    char *orig = dst;
    while ((*dst++ = *src++)) ; /* copies including null */
    return orig;
}

/* Count occurrences using pointer */
int count_char(const char *s, char c) {
    int count = 0;
    while (*s) {
        if (*s == c) count++;
        s++;
    }
    return count;
}

/* Find character using pointer */
const char *my_strchr(const char *s, char c) {
    while (*s) {
        if (*s == c) return s;
        s++;
    }
    return (c == '\0') ? s : NULL;
}

int main(void) {
    const char *msg = "hello world";

    printf("length: %zu\n", my_strlen(msg)); /* 11 */

    char buf[20];
    my_strcpy(buf, msg);
    printf("copy: %s\n", buf); /* hello world */

    printf("'l' count: %d\n", count_char(msg, 'l')); /* 3 */

    const char *found = my_strchr(msg, 'w');
    if (found) {
        printf("found at offset %td: %s\n",
               found - msg, found); /* 6: world */
    }

    /* Idiomatic pointer traversal */
    printf("chars: ");
    for (const char *p = msg; *p; p++) {
        printf("%c ", *p);
    }
    printf("\n");

    return 0;
}

